151|    public void trimToWindow(int maxTokens) {
152|        if (history.isEmpty()) return;
153|        while (estimateTokens() > maxTokens && history.size() > 2) {
154|            int lastUser = history.size() - 1;
155|            while (lastUser > 0 && history.get(lastUser).role() != Role.USER) lastUser--;
156|            if (lastUser <= 0) break;
157|            for (int i = 1; i < history.size(); i++) {
158|                if (i != lastUser) { history.remove(i); break; }
159|            }
160|        }
161|    }
