11|/** 会话上下文：ID 生成（新格式 F9）+ 目录管理（F10）。替代旧 SessionManager。 */
12|public final class SessionContext {
13|    private static final SecureRandom RNG = new SecureRandom();
14|    private static final DateTimeFormatter FMT = DateTimeFormatter.ofPattern("yyyyMMdd-HHmmss");
15|    private static final Pattern ID_PATTERN = Pattern.compile("^(\\d{8}-\\d{6})-[0-9a-fA-F]{4}$");
16|
17|    private SessionContext() {}
18|
19|    /** F9: 生成新 session ID: YYYYMMDD-HHMMSS-xxxx */
20|    public static String newSessionId() {
21|        String ts = LocalDateTime.now().format(FMT);
22|        String rand = String.format("%04x", RNG.nextInt(0xFFFF + 1));
23|        return ts + "-" + rand;
24|    }
