18|/** JSONL 追加写入器（F13-F16）。线程安全。 */
19|public final class SessionWriter implements Closeable {
20|    private static final ObjectMapper json = new ObjectMapper();
21|    private final BufferedWriter writer;
22|    private final FileOutputStream fos;
23|    private final ReentrantLock lock = new ReentrantLock();
24|    private boolean firstLine = true;
25|
26|    public SessionWriter(Path jsonlPath) {
27|        try {
28|            java.nio.file.Files.createDirectories(jsonlPath.getParent());
29|            fos = new FileOutputStream(jsonlPath.toFile(), true); // append mode
30|            writer = new BufferedWriter(new OutputStreamWriter(fos, StandardCharsets.UTF_8));
31|        } catch (Exception e) {
32|            throw new RuntimeException("Failed to open session writer: " + jsonlPath, e);
33|        }
34|    }
35|
36|    public void append(MessageRecord msg, String model) {
37|        lock.lock();
38|        try {
39|            String line = serialize(msg, model);
40|            writer.write(line);
41|            writer.newLine();
42|            writer.flush();
43|            fos.getFD().sync();
44|        } catch (Exception e) {
45|            System.err.println("[session] write failed: " + e.getMessage());
46|        } finally {
47|            lock.unlock();
48|        }
49|    }
50|
51|    public void appendCompactMarker() {
52|        lock.lock();
53|        try {
54|            writer.write("{\"type\":\"compact\",\"ts\":" + (System.currentTimeMillis() / 1000) + "}");
55|            writer.newLine();
56|            writer.flush();
57|            fos.getFD().sync();
58|        } catch (Exception e) {
59|            System.err.println("[session] compact marker write failed: " + e.getMessage());
60|        } finally {
61|            lock.unlock();
62|        }
63|    }
64|
65|    @Override public void close() {
66|        lock.lock();
67|        try { writer.close(); } catch (Exception ignored) {}
68|        finally { lock.unlock(); }
69|    }
70|
71|    private String serialize(MessageRecord msg, String model) {
72|        ObjectNode node = json.createObjectNode();
73|        node.put("role", msg.role().name().toLowerCase());
74|        if (msg.content() != null && !msg.content().isBlank()) {
75|            node.put("content", msg.content());
76|        }
77|        node.put("ts", System.currentTimeMillis() / 1000);
78|        if (firstLine && model != null) {
79|            node.put("model", model);
80|            firstLine = false;
81|        }
82|        // tool_calls
83|        ArrayNode tcArr = null;
84|        for (var b : msg.blocks()) {
85|            if (b instanceof MessageBlock.ToolUseBlock tu) {
86|                if (tcArr == null) tcArr = json.createArrayNode();
87|                ObjectNode tc = json.createObjectNode();
88|                tc.put("id", tu.id());
89|                tc.put("name", tu.name());
90|                tc.set("input", tu.input());
91|                tcArr.add(tc);
92|            }
93|        }
94|        if (tcArr != null) node.set("tool_calls", tcArr);
95|        // tool_results
96|        ArrayNode trArr = null;
97|        for (var b : msg.blocks()) {
98|            if (b instanceof MessageBlock.ToolResultBlock tr) {
99|                if (trArr == null) trArr = json.createArrayNode();
100|                ObjectNode tro = json.createObjectNode();
101|                tro.put("tool_use_id", tr.toolUseId());
102|                tro.put("content", tr.content());
103|                tro.put("is_error", tr.isError());
104|                trArr.add(tro);
105|            }
106|        }
107|        if (trArr != null) node.set("tool_results", trArr);
108|        return node.toString();
109|    }
